import React from 'react';
import { Page, Navbar, List, ListItem, Block, Button, useStore, NavRight } from 'framework7-react';
import store from '../js/store'

const CatalogPage = () => {
  const products = useStore('products');

  const addProduct = () => {
    store.dispatch('addProduct', {
      id: '4',
      title: 'Apple iPhone 12',
      description: 'Lorem ipsum dolor sit amet, consectetur adipisicing elit. Nisi tempora similique reiciendis, error nesciunt vero, blanditiis pariatur dolor, minima sed sapiente rerum, dolorem corrupti hic modi praesentium unde saepe perspiciatis.'
    });
  }

  return (
    <Page name="catalog">
      <Navbar title="Catalog">
        <NavRight>
          <div className="app-menu">
            <div className="app-menu-left">
              <svg t="1617088230903" className="icon" viewBox="0 0 1024 1024" version="1.1"
                   xmlns="http://www.w3.org/2000/svg" p-id="10459" width="64" height="64">
                <path
                  d="M512 512m-99.555556 0a99.555556 99.555556 0 1 0 199.111112 0 99.555556 99.555556 0 1 0-199.111112 0Z"
                  fill="#ffffff" p-id="10460"></path>
                <path
                  d="M227.555556 512m-56.888889 0a56.888889 56.888889 0 1 0 113.777777 0 56.888889 56.888889 0 1 0-113.777777 0Z"
                  fill="#ffffff" p-id="10461"></path>
                <path
                  d="M796.444444 512m-56.888888 0a56.888889 56.888889 0 1 0 113.777777 0 56.888889 56.888889 0 1 0-113.777777 0Z"
                  fill="#ffffff" p-id="10462"></path>
              </svg>
            </div>
            <div className="app-menu-center">
            </div>
            <div className="app-menu-right">
            <svg t="1617087938395" className="icon" viewBox="0 0 1024 1024" version="1.1"
                 xmlns="http://www.w3.org/2000/svg" p-id="9654" data-spm-anchor-id="a313x.7781069.0.i16" width="64"
                 height="64">
              <path
                d="M512 0c281.6 0 512 230.4 512 512s-230.4 512-512 512-512-230.4-512-512 230.4-512 512-512z m0 121.6C294.4 121.6 121.6 294.4 121.6 512s172.8 390.4 390.4 390.4 390.4-172.8 390.4-390.4S729.6 121.6 512 121.6z m0 236.8c83.2 0 153.6 70.4 153.6 153.6S595.2 665.6 512 665.6 358.4 595.2 358.4 512 428.8 358.4 512 358.4z"
                fill="#ffffff" p-id="9655" data-spm-anchor-id="a313x.7781069.0.i17" className="selected"></path>
            </svg>
            </div>
          </div>
        </NavRight>
      </Navbar>
      <List>
        {products.map((product) => (
          <ListItem
            key={product.id}
            title={product.title}
            link={`/product/${product.id}/`}
          />
        ))}
      </List>
      {products.length === 3 && (
        <Block>
          <Button fill onClick={addProduct}>Add Product</Button>
        </Block>
      )}
    </Page>
  );
}

export default CatalogPage;
