let f7 = null

export const set = instance => f7 = instance
export const get = () => f7

export const alert = (msg, duration = 0) => {
  if (f7) {
    const dialog = f7.dialog.alert(msg,'提示')
    if (duration > 0) {
      setTimeout(() => dialog.close(), duration)
    }
  }
}
export const toast = (msg, duration = 2000) => {
  if (f7) {
    const toast = f7.toast.create({
      text: msg,
      position: 'center',
      closeTimeout: duration,
    })
    toast.open()
  }
}
export const routeChange = (params) => {
  console.log(params,111)
  // const flag = params.router.routes.some(item=>{
  //   if(item.path === params.to.route.path) {
  //     return true
  //   }
  // })
  const flag = params.to.route.path !== '(.*)' || params.to.path === '(.*)'
  if(flag) {
    params.resolve()
  }else{
    window.history.pushState({}, params.to.path, params.to.path);
  }
}

export const showLoading = () => f7 && f7.preloader.show()
export const hideLoading = () => f7 && f7.preloader.hide()
