import React, { useState } from 'react';
import {
  Page,
  Navbar,
  NavRight,
  List,
  ListInput,
  ListItem,
  Toggle,
  BlockTitle,
  Row,
  Button,
  Icon,
  Range,
  Block
} from 'framework7-react';

const SettingsPage = (props) => {
  const [func, setFunc] = useState([
    {
      label: '是否登陆',
      func: () => {
        navigator.autologin.isLogin(res => {
          console.log(res)
      })
      }
    }
  ])
  return <Page name="settings">
    <Navbar title="Settings">
      <NavRight>
        <Icon f7="qrcode_viewfinders"></Icon>
    </NavRight>
    </Navbar>

    <BlockTitle>demo测试</BlockTitle>
    <Block strong>
      <Row tag="p">
        <Button className="col" large raised>是否登陆</Button>
        <Button className="col" large raised>Large</Button>
      </Row>
      <Row tag="p">
        <Button className="col" large raised>Large</Button>
        <Button className="col" large raised>Large</Button>
      </Row>
    </Block>
  </Page>
}

export default SettingsPage;
